@RestController
@RequestMapping("/api")
class AccountController {

    private val requestCounter = ConcurrentHashMap<String, MutableList<Long>>()

    @GetMapping("/me")
    fun getAccount(@RequestHeader("X-Client-Id", required = false) clientId: String?): ResponseEntity<Map<String, Any>> {
        val effectiveClientId = clientId ?: "unknown"
        rateLimit(effectiveClientId)

        val requestId = generateRequestId()
        auditLog("INFO", requestId, "account_view", mapOf("clientId" to effectiveClientId))

        val body = mapOf(
            "id" to "123",
            "email" to "user@example.com",
            "requestedAt" to Instant.now().toString()
        )
        return ResponseEntity.ok()
            .header("X-Request-Id", requestId)
            .body(body)
    }

    private fun rateLimit(clientId: String, limit: Int = 60, windowSeconds: Long = 60) {
        val now = System.currentTimeMillis()
        val windowStart = now - (windowSeconds * 1000)
        val timestamps = requestCounter.computeIfAbsent(clientId) { mutableListOf() }

        synchronized(timestamps) {
            timestamps.removeIf { it < windowStart }
            if (timestamps.size >= limit) {
                auditLog("WARN", generateRequestId(), "rate_limit_exceeded", mapOf("clientId" to clientId))
                throw ResponseStatusException(HttpStatus.TOO_MANY_REQUESTS, "Rate limit exceeded")
            }
            timestamps.add(now)
        }
    }

    private fun auditLog(level: String, requestId: String, event: String, details: Map<String, Any>) {
        // In production, send to structured logging / SIEM
        println("[$level] reqId=$requestId event=$event details=$details")
    }

    private fun generateRequestId(): String =
        java.util.UUID.randomUUID().toString()
}

