import io.ktor.server.application.*
import io.ktor.server.engine.embeddedServer
import io.ktor.server.netty.Netty
import io.ktor.server.request.*
import io.ktor.server.response.*
import io.ktor.server.routing.*
import io.ktor.server.sessions.*
import io.ktor.server.auth.*
import io.ktor.http.*
import org.mindrot.jbcrypt.BCrypt

// Strongly-typed principal used by Ktor auth
data class UserPrincipal(val username: String, val isAdmin: Boolean) : Principal

data class UserSession(val username: String, val isAdmin: Boolean)

data class LoginRequest(val username: String, val password: String)

data class StoredUser(val username: String, val passwordHash: String, val isAdmin: Boolean)

// Users with BCRYPT-hashed passwords (pretend these are loaded from a DB)
val storedUsers = listOf(
    StoredUser("alice", BCrypt.hashpw("password123", BCrypt.gensalt()), false),
    StoredUser("admin", BCrypt.hashpw("S3cureAdm1n!", BCrypt.gensalt()), true)
).associateBy { it.username }

fun main() {
    embeddedServer(Netty, port = 8080) {
        install(Sessions) {
            cookie<UserSession>("SESSION") {
                cookie.httpOnly = true
                cookie.secure = true
                cookie.extensions["SameSite"] = "Lax"
            }
        }

        install(Authentication) {
            session<UserSession>("auth-session") {
                validate { session ->
                    val dbUser = storedUsers[session.username]
                    if (dbUser != null && dbUser.isAdmin == session.isAdmin) {
                        UserPrincipal(dbUser.username, dbUser.isAdmin)
                    } else {
                        null
                    }
                }
                challenge {
                    call.respond(HttpStatusCode.Unauthorized, "Not authenticated")
                }
            }
        }

        routing {
            post("/login") {
                val login = call.receive<LoginRequest>()
                val dbUser = storedUsers[login.username]

                // PRIMARY DEFENSE: verify hashed password
                if (dbUser != null && BCrypt.checkpw(login.password, dbUser.passwordHash)) {
                    // Never trust client to set isAdmin
                    call.sessions.set(UserSession(dbUser.username, dbUser.isAdmin))
                    call.respondText("Logged in as ${'$'}{dbUser.username}")
                } else {
                    // Generic error message to avoid user enumeration
                    call.respond(HttpStatusCode.Unauthorized, "Invalid username or password")
                }
            }

            authenticate("auth-session") {
                get("/me") {
                    val principal = call.principal<UserPrincipal>()!!
                    call.respondText("Hello, ${'$'}{principal.username}, admin=${'$'}{principal.isAdmin}")
                }

                get("/admin") {
                    val principal = call.principal<UserPrincipal>()!!
                    if (!principal.isAdmin) {
                        call.respond(HttpStatusCode.Forbidden, "Admins only")
                    } else {
                        call.respondText("Welcome, admin ${'$'}{principal.username}")
                    }
                }
            }

            post("/logout") {
                call.sessions.clear<UserSession>()
                call.respondText("Logged out")
