**Key Security Controls**:
- Uses Ktor's `Authentication` feature with `session` auth and `Principal` objects, centralizing authentication logic and avoiding ad-hoc checks.
- Stores only bcrypt-hashed passwords in the user store and verifies them with `BCrypt.checkpw`, mitigating impact of credential database leaks.
- Derives authorization state (`isAdmin`) exclusively from trusted server-side user records and secures the session cookie with `HttpOnly`, `Secure`, and `SameSite` attributes to reduce theft and tampering risk.

In production, you typically combine secure credential handling, JWT-based stateless auth, strong session and cookie settings, and operational controls like rate limiting and audit logging.

**PRODUCTION PATTERN**:

```kotlin
import io.ktor.server.application.*
import io.ktor.server.engine.embeddedServer
import io.ktor.server.netty.Netty
import io.ktor.server.request.*
import io.ktor.server.response.*
import io.ktor.server.routing.*
import io.ktor.server.auth.*
import io.ktor.server.auth.jwt.*
import io.ktor.server.sessions.*
import io.ktor.http.*
import org.mindrot.jbcrypt.BCrypt
import java.time.Instant
import java.util.concurrent.ConcurrentHashMap

// ---- Domain & Security Models ----

data class User(
    val id: String,
    val username: String,
    val passwordHash: String,
    val roles: Set<String>, // e.g. ["USER"], ["USER","ADMIN"]
    val disabled: Boolean = false
)

// Principal extracted from JWT
class JwtUserPrincipal(
    val userId: String,
    val username: String,
    val roles: Set<String>
) : Principal

// Simple login request
data class LoginRequest(val username: String, val password: String)

// In-memory user store for demo (use a real DB in production)
val usersByUsername: Map<String, User> = listOf(
    User("1", "alice", BCrypt.hashpw("Password#123", BCrypt.gensalt()), setOf("USER")),
    User("2", "admin", BCrypt.hashpw("Sup3rS3cret!", BCrypt.gensalt()), setOf("USER", "ADMIN"))
).associateBy { it.username }

// Basic in-memory rate limiting per IP / username (for demo only)
object LoginRateLimiter {
    private val attempts = ConcurrentHashMap<String, MutableList<Long>>()
    private const val WINDOW_MILLIS = 60_000 // 1 minute
    private const val MAX_ATTEMPTS = 5

    fun allow(key: String): Boolean {
        val now = System.currentTimeMillis()
        val list = attempts.computeIfAbsent(key) { mutableListOf() }
        synchronized(list) {
            list.removeIf { it < now - WINDOW_MILLIS }
            return if (list.size >= MAX_ATTEMPTS) {
                false
            } else {
                list += now
                true
            }
        }
    }
}

fun Application.module() {
    val jwtIssuer = environment.config.property("jwt.issuer").getString()
    val jwtAudience = environment.config.property("jwt.audience").getString()
    val jwtRealm = environment.config.property("jwt.realm").getString()
    val jwtSecret = environment.config.property("jwt.secret").getString()

    install(Sessions) {
        // Optional short-lived CSRF/session cookie if needed for web clients
        cookie<String>("CSRF_TOKEN") {
            cookie.httpOnly = true
            cookie.secure = environment.developmentMode.not()
            cookie.extensions["SameSite"] = "Strict"
        }
    }

    install(Authentication) {
        jwt("auth-jwt") {
            realm = jwtRealm
            verifier(
                JwtUtil.makeVerifier(
                    secret = jwtSecret,
                    issuer = jwtIssuer,
                    audience = jwtAudience
                )
            )
            validate { credential ->
                val username = credential.payload.getClaim("username").asString()
                val roles = credential.payload.getClaim("roles").asList(String::class.java)?.toSet() ?: emptySet()
                val userId = credential.payload.subject

                if (username != null && userId != null && roles.isNotEmpty()) {
                    JwtUserPrincipal(userId, username, roles)
                } else {
                    null
                }
            }
            challenge { _, _ ->
                call.respond(HttpStatusCode.Unauthorized, "Invalid or expired token")
            }
        }
    }

    routing {
        // Health check with minimal info
        get("/health") {
            call.respondText("OK")
        }

        post("/login") {
            val clientIp = call.request.origin.remoteHost
            if (!LoginRateLimiter.allow(clientIp)) {
                // RATE LIMIT: avoid brute force
                call.application.environment.log.warn("Login rate limit exceeded from ${'$'}clientIp")
                call.respond(HttpStatusCode.TooManyRequests, "Too many login attempts. Try again later.")
                return@post
            }

            val login = runCatching { call.receive<LoginRequest>() }.getOrElse {
                call.respond(HttpStatusCode.BadRequest, "Invalid request body")
                return@post
            }

            val user = usersByUsername[login.username]
            if (user == null || user.disabled) {
                // Avoid user enumeration
                call.application.environment.log.info("Failed login for unknown/disabled user: ${'$'}{login.username} from ${'$'}clientIp")
                call.respond(HttpStatusCode.Unauthorized, "Invalid username or password")
                return@post
            }

            if (!BCrypt.checkpw(login.password, user.passwordHash)) {
                call.application.environment.log.info("Failed login (bad password) for user: ${'$'}{user.username} from ${'$'}clientIp")
                call.respond(HttpStatusCode.Unauthorized, "Invalid username or password")
                return@post
            }

            // Successful login: issue short-lived JWT
            val token = JwtUtil.createToken(
                secret = jwtSecret,
                issuer = jwtIssuer,
                audience = jwtAudience,
                subject = user.id,
                username = user.username,
                roles = user.roles,
                expiresInSeconds = 15 * 60 // 15 minutes
            )

            call.application.environment.log.info("Successful login for user: ${'$'}{user.username} from ${'$'}clientIp")

            call.respond(mapOf(
                "token" to token,
                "expiresAt" to Instant.now().plusSeconds(15 * 60).toString()
            ))
        }

        authenticate("auth-jwt") {
            get("/me") {
                val principal = call.principal<JwtUserPrincipal>()!!
                call.respond(mapOf(
                    "userId" to principal.userId,
                    "username" to principal.username,
                    "roles" to principal.roles
                ))
            }

            get("/admin/dashboard") {
                val principal = call.principal<JwtUserPrincipal>()!!
                if (!principal.roles.contains("ADMIN")) {
                    call.application.environment.log.warn(
                        "Forbidden admin access attempt by ${'$'}{principal.username}"
                    )
                    call.respond(HttpStatusCode.Forbidden, "Admins only")
                    return@get
                }
                call.respond(mapOf("message" to "Secure admin data"))
            }
        }

        // Graceful handling of unknown routes
        route("/") {
            handle {
                call.respond(HttpStatusCode.NotFound, "Not found")
            }
        }
    }
}

// ---- JWT Utility (separate file in real apps) ----

import com.auth0.jwt.JWT
import com.auth0.jwt.algorithms.Algorithm
import com.auth0.jwt.interfaces.JWTVerifier

object JwtUtil {
    fun makeVerifier(secret: String, issuer: String, audience: String): JWTVerifier {
        val algorithm = Algorithm.HMAC256(secret)
        return JWT.require(algorithm)
            .withIssuer(issuer)
            .withAudience(audience)
            .build()
    }

    fun createToken(
        secret: String,
        issuer: String,
        audience: String,
        subject: String,
        username: String,
        roles: Set<String>,
        expiresInSeconds: Long
    ): String {
        val algorithm = Algorithm.HMAC256(secret)
        val now = Instant.now()
        return JWT.create()
            .withIssuer(issuer)
            .withAudience(audience)
            .withSubject(subject)
            .withIssuedAt(java.util.Date.from(now))
            .withExpiresAt(java.util.Date.from(now.plusSeconds(expiresInSeconds)))
            .withClaim("username", username)
            .withArrayClaim("roles", roles.toTypedArray())
            .sign(algorithm)
    }
}
```

**Defense in Depth Layers**:
1. Strong authentication & credential handling
   - `BCrypt.checkpw(login.password, user.passwordHash)` ensures passwords are never stored or compared in plaintext, significantly reducing the impact of database leaks.
   - Disabled accounts and generic error messages (`"Invalid username or password"`) prevent easy user enumeration and help respond to compromised accounts.

2. Token-based authorization with role checks
   - JWTs contain `roles` and `userId` claims, and endpoints explicitly enforce roles:
   ```kotlin
   if (!principal.roles.contains("ADMIN")) {
       call.respond(HttpStatusCode.Forbidden, "Admins only")
   }
   ```
   - Ktor's `jwt("auth-jwt")` validation makes sure tokens are signed, not expired, and match issuer/audience, stopping token forgery or reuse across services.

3. Operational safeguards: rate limiting and logging
   - Simple rate limiting to slow brute-force attacks:
   ```kotlin
   if (!LoginRateLimiter.allow(clientIp)) {
       call.respond(HttpStatusCode.TooManyRequests)
       return@post
   }
   ```
   - Structured audit logging of successes, failures, and forbidden access attempts enables incident response and anomaly detection:
   ```kotlin
   call.application.environment.log.info("Successful login for user: ${'$'}{user.username} from ${'$'}clientIp")
   call.application.environment.log.warn("Forbidden admin access attempt by ${'$'}{principal.username}")
   ```

**Additional Protections**:
- Environment-specific configuration: only enable `cookie.secure` and strict SameSite in non-development, keep JWT secret and DB credentials in environment variables or a secrets manager, not in source code.
- Add HTTP security headers (via Ktor plugins or custom middleware) such as `Strict-Transport-Security`, `X-Content-Type-Options`, and `Content-Security-Policy` to reduce XSS and downgrade attacks that could expose tokens.
- Implement token rotation and refresh tokens with revocation lists for longer-lived sessions, plus anomaly detection (e.g., impossible travel, sudden IP / device change) to invalidate tokens and alert on suspicious behavior.

Custom authentication logic in Spring Security can easily introduce critical bypasses if you skip the framework's established mechanisms.

**VULNERABLE CODE**:

```kotlin
package com.example.demo

import org.springframework.http.HttpStatus
import org.springframework.http.ResponseEntity
import org.springframework.web.bind.annotation.*
import javax.servlet.http.HttpSession

@RestController
@RequestMapping("/api")
class AuthController {

    // Hard‑coded users, no password hashing, no account lockout
    private val users = mapOf(
        "admin" to "admin123", // plaintext password
        "user" to "password"   // plaintext password
    )

    @PostMapping("/login")
    fun login(
        @RequestParam username: String?,
        @RequestParam password: String?,
        session: HttpSession
    ): ResponseEntity<String> {
        // VULNERABLE: trusts a flag instead of checking credentials
        if (session.getAttribute("isDebug") == true) {
            session.setAttribute("user", "admin")
            return ResponseEntity.ok("Logged in as admin (debug)")
        }

        // VULNERABLE: nulls treated as empty string, no timing protection
        val pwd = password ?: ""
        val expected = users[username]
        if (expected != null && expected == pwd) {
            session.setAttribute("user", username)
            return ResponseEntity.ok("Logged in")
        }

        // VULNERABLE: generic 200 with error message (no rate limiting)
        return ResponseEntity("Invalid credentials", HttpStatus.OK)
    }

    @GetMapping("/admin")
    fun admin(session: HttpSession): ResponseEntity<String> {
        // VULNERABLE: only checks non‑null, no role separation
        val user = session.getAttribute("user") as String?
        return if (user != null) {
            ResponseEntity.ok("Welcome to admin page, $user")
        } else {
            ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Please login")
        }
    }
}
```

**Attack Payload** (HTTP request exploiting the debug bypass):
```bash
curl -i -c cookies.txt -X POST "https://victim.example.com/api/login" \
  -d "username=anything&password=anything" \
  -H "Cookie: JSESSIONID=xyz; isDebug=true"
```

This payload forges the `isDebug` session attribute (e.g., via prior session fixation or a misconfigured debug endpoint) so the server logs the attacker in as `admin` without checking the password.

**Why This Is Dangerous**:
- Debug/backdoor flag (`isDebug`) allows bypassing password checks, leading to full authentication bypass.
- Plaintext passwords and no integration with Spring Security disable protections like hashing, lockout, and CSRF.
- Authorization is based only on a generic `user` session attribute, so any logged-in user can access `/admin`.

