package com.example.demo

import org.springframework.context.annotation.Bean
import org.springframework.context.annotation.Configuration
import org.springframework.http.HttpStatus
import org.springframework.http.ResponseEntity
import org.springframework.security.authentication.AuthenticationManager
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity
import org.springframework.security.config.annotation.web.builders.HttpSecurity
import org.springframework.security.core.Authentication
import org.springframework.security.core.authority.SimpleGrantedAuthority
import org.springframework.security.core.userdetails.User
import org.springframework.security.core.userdetails.UserDetails
import org.springframework.security.core.userdetails.UserDetailsService
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder
import org.springframework.security.crypto.password.PasswordEncoder
import org.springframework.security.web.SecurityFilterChain
import org.springframework.web.bind.annotation.*
import javax.servlet.http.HttpSession

@Configuration
@EnableMethodSecurity
class SecurityConfig {

    @Bean
    fun passwordEncoder(): PasswordEncoder = BCryptPasswordEncoder()

    // PRIMARY DEFENSE: Use UserDetailsService with hashed passwords and roles
    @Bean
    fun userDetailsService(passwordEncoder: PasswordEncoder): UserDetailsService {
        val admin: UserDetails = User.withUsername("admin")
            .password(passwordEncoder.encode("AdminStrongP@ss!"))
            .authorities(SimpleGrantedAuthority("ROLE_ADMIN"))
            .build()

        val user: UserDetails = User.withUsername("user")
            .password(passwordEncoder.encode("UserStr0ngP@ss"))
            .authorities(SimpleGrantedAuthority("ROLE_USER"))
            .build()

        val users = mapOf(
            admin.username to admin,
            user.username to user
        )

        return UserDetailsService { username ->
            users[username] ?: throw RuntimeException("User not found")
        }
    }

    @Bean
    fun filterChain(http: HttpSecurity): SecurityFilterChain {
        // PRIMARY DEFENSE: Let Spring Security manage authentication/session
        http
            .csrf { it.disable() } // For stateless APIs; enable for browser forms
            .authorizeHttpRequests { auth ->
                auth
                    .requestMatchers("/api/login").permitAll()
                    .requestMatchers("/api/admin").hasRole("ADMIN")
                    .anyRequest().authenticated()
            }
            .formLogin { it.disable() }
            .httpBasic { it.disable() }

        return http.build()
    }

    @Bean
    fun authenticationManager(config: AuthenticationConfiguration): AuthenticationManager =
        config.authenticationManager
}

@RestController
@RequestMapping("/api")
class SecureAuthController(
    private val authenticationManager: AuthenticationManager
) {

    data class LoginRequest(val username: String?, val password: String?)
    data class LoginResponse(val message: String)

    @PostMapping("/login")
    fun login(
        @RequestBody body: LoginRequest,
        session: HttpSession
    ): ResponseEntity<LoginResponse> {
        val username = body.username?.trim() ?: ""
        val password = body.password ?: ""

        if (username.isEmpty() || password.isEmpty()) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(LoginResponse("Username and password are required"))
        }

        return try {
            // PRIMARY DEFENSE: Delegate credential check to AuthenticationManager
            val authToken = UsernamePasswordAuthenticationToken(username, password)
            val authentication: Authentication = authenticationManager.authenticate(authToken)

            // DEFENSE IN DEPTH: Store only minimal user info in session
            session.setAttribute("SPRING_SECURITY_CONTEXT", authentication)

            ResponseEntity.ok(LoginResponse("Login successful"))
        } catch (ex: Exception) {
            // DEFENSE IN DEPTH: Do not reveal which field was wrong
            // Log securely in real app (omitted console log here)
            ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                .body(LoginResponse("Invalid username or password"))
        }
    }

    @GetMapping("/admin")
    fun admin(): ResponseEntity<LoginResponse> {
        // Access control enforced by Spring Security config (hasRole("ADMIN"))
        return ResponseEntity.ok(LoginResponse("Welcome to admin page"))
    }
