```kotlin
package com.example.demo

import org.slf4j.LoggerFactory
import org.springframework.beans.factory.annotation.Value
import org.springframework.context.annotation.Bean
import org.springframework.context.annotation.Configuration
import org.springframework.http.HttpStatus
import org.springframework.http.ResponseEntity
import org.springframework.security.authentication.AuthenticationManager
import org.springframework.security.authentication.BadCredentialsException
import org.springframework.security.authentication.LockedException
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity
import org.springframework.security.config.annotation.web.builders.HttpSecurity
import org.springframework.security.core.Authentication
import org.springframework.security.core.userdetails.UserDetailsService
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder
import org.springframework.security.crypto.password.PasswordEncoder
import org.springframework.security.web.SecurityFilterChain
import org.springframework.security.web.session.SessionManagementFilter
import org.springframework.stereotype.Component
import org.springframework.web.bind.annotation.*
import java.time.Instant
import java.util.concurrent.ConcurrentHashMap
import javax.servlet.http.HttpServletRequest
import javax.servlet.http.HttpSession

@Configuration
@EnableMethodSecurity
class ProdSecurityConfig(
    private val userDetailsService: UserDetailsService
) {

    @Bean
    fun passwordEncoder(): PasswordEncoder = BCryptPasswordEncoder(12)

    @Bean
    fun filterChain(http: HttpSecurity): SecurityFilterChain {
        http
            .csrf { it.disable() } // For pure APIs; otherwise enable and configure
            .sessionManagement { sm ->
                sm.sessionFixation { fixation -> fixation.migrateSession() }
                sm.maximumSessions(1)
            }
            .authorizeHttpRequests { auth ->
                auth
                    .requestMatchers("/api/login").permitAll()
                    .requestMatchers("/api/admin").hasRole("ADMIN")
                    .anyRequest().authenticated()
            }
            // Add custom logging filter early in the chain
            .addFilterBefore(AuthLoggingFilter(), SessionManagementFilter::class.java)

        return http.build()
    }

    @Bean
    fun authenticationManager(config: AuthenticationConfiguration): AuthenticationManager =
        config.authenticationManager
}

@Component
class BruteForceProtection {
    private val attempts = ConcurrentHashMap<String, MutableList<Instant>>()
    private val logger = LoggerFactory.getLogger(BruteForceProtection::class.java)

    // Allow 5 attempts per 5 minutes per IP
    private val maxAttempts = 5
    private val windowSeconds = 300L

    fun recordAttempt(ip: String) {
        val now = Instant.now()
        val list = attempts.computeIfAbsent(ip) { mutableListOf() }
        synchronized(list) {
            list.add(now)
            val cutoff = now.minusSeconds(windowSeconds)
            list.removeIf { it.isBefore(cutoff) }
        }
    }

    fun isBlocked(ip: String): Boolean {
        val now = Instant.now()
        val list = attempts[ip] ?: return false
        synchronized(list) {
            val cutoff = now.minusSeconds(windowSeconds)
            list.removeIf { it.isBefore(cutoff) }
            val blocked = list.size >= maxAttempts
            if (blocked) {
                logger.warn("IP {} temporarily blocked due to brute-force suspicion", ip)
            }
            return blocked
        }
    }
}

@RestController
@RequestMapping("/api")
class ProdAuthController(
    private val authenticationManager: AuthenticationManager,
    private val bruteForceProtection: BruteForceProtection,
    @Value("\${spring.profiles.active:dev}") private val activeProfile: String
) {

    data class LoginRequest(val username: String?, val password: String?)
    data class LoginResponse(val message: String)

    private val logger = LoggerFactory.getLogger(ProdAuthController::class.java)

    @PostMapping("/login")
    fun login(
        @RequestBody body: LoginRequest,
        request: HttpServletRequest,
        session: HttpSession
    ): ResponseEntity<LoginResponse> {
        val clientIp = request.remoteAddr ?: "unknown"

        if (bruteForceProtection.isBlocked(clientIp)) {
            logger.warn("Blocked login attempt from {} due to brute-force rule", clientIp)
            return ResponseEntity.status(HttpStatus.TOO_MANY_REQUESTS)
                .body(LoginResponse("Too many attempts. Please try again later."))
        }

        val username = body.username?.trim().orEmpty()
        val password = body.password.orEmpty()

        if (username.isEmpty() || password.isEmpty()) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(LoginResponse("Username and password are required"))
        }

        bruteForceProtection.recordAttempt(clientIp)

        return try {
            val authToken = UsernamePasswordAuthenticationToken(username, password)
            val authentication: Authentication = authenticationManager.authenticate(authToken)

            // Regenerate session ID on successful login (session fixation defense)
            session.invalidate()
            val newSession = request.getSession(true)
            newSession.setAttribute("SPRING_SECURITY_CONTEXT", authentication)

            if (activeProfile == "prod") {
                logger.info(
                    "Successful login for user='{}' ip='{}' roles={}",
                    username,
                    clientIp,
                    authentication.authorities
                )
            }

            ResponseEntity.ok(LoginResponse("Login successful"))
        } catch (ex: LockedException) {
            logger.warn("Locked account login for user='{}' ip='{}'", username, clientIp)
            ResponseEntity.status(HttpStatus.LOCKED)
                .body(LoginResponse("Account is locked. Contact support."))
        } catch (ex: BadCredentialsException) {
            logger.warn("Bad credentials for user='{}' ip='{}'", username, clientIp)
            ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                .body(LoginResponse("Invalid username or password"))
        } catch (ex: Exception) {
            logger.error("Authentication error for user='{}' ip='{}'", username, clientIp)
            ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(LoginResponse("Authentication service error"))
        }
    }

    @GetMapping("/admin")
    fun admin(): ResponseEntity<LoginResponse> =
        ResponseEntity.ok(LoginResponse("Welcome to admin page"))
}

class AuthLoggingFilter : javax.servlet.Filter {
    private val logger = LoggerFactory.getLogger(AuthLoggingFilter::class.java)

    override fun doFilter(
        request: javax.servlet.ServletRequest,
        response: javax.servlet.ServletResponse,
        chain: javax.servlet.FilterChain
    ) {
        val httpReq = request as HttpServletRequest
        if (httpReq.requestURI.endsWith("/login")) {
            logger.debug("Incoming auth request from ip='{}' path='{}'", httpReq.remoteAddr, httpReq.requestURI)
        }
        chain.doFilter(request, response)
    }
}
```

**Defense in Depth Layers**:
1. **Brute-force protection & rate limiting**:
   - `BruteForceProtection` tracks attempts per IP and returns HTTP 429 when thresholds are exceeded:
   ```kotlin
   if (bruteForceProtection.isBlocked(clientIp)) {
       return ResponseEntity.status(HttpStatus.TOO_MANY_REQUESTS)
           .body(LoginResponse("Too many attempts. Please try again later."))
   }
   ```
2. **Secure session handling & fixation defense**:
   - On successful auth, invalidate the old session and create a new one:
   ```kotlin
   session.invalidate()
   val newSession = request.getSession(true)
   newSession.setAttribute("SPRING_SECURITY_CONTEXT", authentication)
   ```
3. **Audit logging & environment-aware behavior**:
   - Log successful and failed logins with user, IP, and roles, but only at info level in production:
   ```kotlin
   if (activeProfile == "prod") {
       logger.info("Successful login for user='{}' ip='{}' roles={}", username, clientIp, authentication.authorities)
   }
   ```

**Additional Protections**:
- Configure environment-specific security (e.g., stronger BCrypt cost and stricter logging in `prod`, more verbose debug only in `dev`).
- Enforce security headers and TLS termination at the edge (e.g., via Spring Boot `server.ssl.*` or a reverse proxy) to protect credentials in transit.
- Integrate with central monitoring/alerting (e.g., pushing auth logs to SIEM) to detect anomalous login patterns, credential stuffing, or targeted attacks early.

A simple JWT check can be very unsafe if you don't verify the signature properly, validate standard claims (issuer, audience, expiration), and restrict allowed algorithms. Misconfigured JWT validation has led to real-world account takeovers.

**VULNERABLE CODE**:

```kotlin
import io.ktor.application.*
import io.ktor.http.*
import io.ktor.request.*
import io.ktor.response.*
import io.ktor.routing.*
import kotlinx.serialization.*
import kotlinx.serialization.json.Json

@Serializable
data class JwtPayload(val sub: String, val role: String? = null)

fun Application.vulnerableJwtModule() {
    routing {
        get("/v1/profile") {
            val authHeader = call.request.headers[HttpHeaders.Authorization]
            if (authHeader == null || !authHeader.startsWith("Bearer ")) {
                call.respond(HttpStatusCode.Unauthorized, "Missing token")
                return@get
            }

            // VULNERABLE: blindly trust the JWT without verifying signature
            val token = authHeader.removePrefix("Bearer ").trim()
            val parts = token.split(".")
            if (parts.size != 3) {
                call.respond(HttpStatusCode.BadRequest, "Malformed token")
                return@get
            }

            val payloadJson = String(java.util.Base64.getUrlDecoder().decode(parts[1]))
            val payload = Json.decodeFromString<JwtPayload>(payloadJson)

            // No signature verification, no exp/iss/aud checks
            call.respond(HttpStatusCode.OK, "Hello, user ${payload.sub} with role ${payload.role}")
        }
    }
}
```

**Attack Payload** (forged JWT without valid signature):
```text
Bearer eyJhbGciOiJub25lIn0.eyJzdWIiOiJhZG1pbiIsInJvbGUiOiJBRE1JTiJ9.
```

- Header (Base64URL): `{"alg":"none"}`
- Payload (Base64URL): `{"sub":"admin","role":"ADMIN"}`
- No valid signature: attacker sets empty/garbage third part

This lets an attacker call `/v1/profile` as `admin` because the server never verifies the signature or algorithm.

**Why This Is Dangerous**:
- Accepts any token with a `sub` field, even if it was never issued by your server
- No protection against tampering: attacker can change the role to `ADMIN` and gain elevated privileges
- No expiration (`exp`) or audience (`aud`) checks, so tokens can be replayed indefinitely and across services

**SECURE VERSION**:

```kotlin
import io.ktor.application.*
import io.ktor.auth.*
import io.ktor.auth.jwt.*
import io.ktor.http.*
import io.ktor.response.*
import io.ktor.routing.*
import com.auth0.jwt.JWT
import com.auth0.jwt.algorithms.Algorithm
import org.slf4j.LoggerFactory

fun Application.secureJwtModule() {
    val log = LoggerFactory.getLogger("SecureJwtModule")

    val jwtIssuer = environment.config.property("jwt.issuer").getString()
    val jwtAudience = environment.config.property("jwt.audience").getString()
    val jwtSecret = environment.config.property("jwt.secret").getString()

    install(Authentication) {
        jwt("auth-jwt") {
            realm = "example-api"

            val algorithm = Algorithm.HMAC256(jwtSecret)

            verifier(
                JWT
                    .require(algorithm)
                    .withIssuer(jwtIssuer)
                    .withAudience(jwtAudience)
                    .acceptLeeway(5) // small clock skew
                    .build()
            )

            validate { credential ->
                val subject = credential.payload.subject
                if (subject.isNullOrBlank()) {
                    log.warn("JWT validation failed: missing subject")
                    null
                } else {
                    JWTPrincipal(credential.payload)
                }
            }

            challenge { _, _ ->
                call.respond(HttpStatusCode.Unauthorized, "Invalid or expired token")
            }
        }
    }

    routing {
        authenticate("auth-jwt") {
            get("/v1/profile") {
                val principal = call.principal<JWTPrincipal>()
                val username = principal!!.payload.getClaim("sub").asString()
                val role = principal.payload.getClaim("role").asString() ?: "USER"

                log.info("Profile accessed by $username with role $role")
                call.respond(HttpStatusCode.OK, "Hello, $username (role=$role)")
            }
        }
    }
}
```

**Key Security Controls**:
- **Signature and algorithm verification** with `Algorithm.HMAC256(jwtSecret)` and `JWT.require(algorithm)`: ensures tokens are signed with your secret using a specific algorithm, preventing `alg=none` and tampering.
- **Claim validation** (`withIssuer`, `withAudience`, built-in `exp` check): only accepts tokens issued by your service for the correct audience and still within their validity period.
- **Secure error handling and logging**: logs failed validations for monitoring while returning generic error messages to clients, avoiding information leakage and supporting incident response.

In production, JWT handling needs to account for key rotation, multiple audiences/services, role-based access control, and strong monitoring. Centralize token issuance, validate strictly at each service, and design for keys to change without downtime.

**PRODUCTION PATTERN**:

```kotlin
import io.ktor.application.*
import io.ktor.auth.*
import io.ktor.auth.jwt.*
import io.ktor.http.*
import io.ktor.response.*
import io.ktor.routing.*
import org.slf4j.LoggerFactory
import com.auth0.jwt.JWT
import com.auth0.jwt.algorithms.Algorithm
import java.time.Instant

// Represents a loaded public key / secret with key id (kid)
data class JwtKey(val kid: String, val algorithm: Algorithm)

class JwtKeyProvider(private val app: Application) {
    private val log = LoggerFactory.getLogger(JwtKeyProvider::class.java)
    @Volatile
    private var keys: Map<String, JwtKey> = loadKeysFromConfig()

    fun getAlgorithm(kid: String?): Algorithm? {
        if (kid == null) return null
        return keys[kid]?.algorithm
    }

    // In real prod: fetch from JWKS endpoint or secret manager, with caching
    private fun loadKeysFromConfig(): Map<String, JwtKey> {
        val config = app.environment.config.config("jwt")
        val activeKid = config.property("activeKid").getString()
        val secret = config.property("secrets.$activeKid").getString()
        log.info("Loaded JWT key with kid=$activeKid")
        return mapOf(activeKid to JwtKey(activeKid, Algorithm.HMAC256(secret)))
    }

    fun rotateKeys() {
        // Called by a scheduled job or admin endpoint (with strong auth)
        log.info("Reloading JWT keys for rotation")
        keys = loadKeysFromConfig()
    }
}

fun Application.productionJwtModule() {
    val log = LoggerFactory.getLogger("ProductionJwtModule")

    val jwtConfig = environment.config.config("jwt")
    val issuer = jwtConfig.property("issuer").getString()
    val audience = jwtConfig.property("audience").getString()
    val keyProvider = JwtKeyProvider(this)

    install(Authentication) {
        jwt("auth-jwt") {
            realm = "prod-api"

            verifier { token ->
                val kid = token.header.get("kid") as String?
                val algorithm = keyProvider.getAlgorithm(kid)
                    ?: throw IllegalArgumentException("Unknown kid: $kid")

                JWT.require(algorithm)
                    .withIssuer(issuer)
                    .withAudience(audience)
                    .acceptLeeway(10)
                    .build()
            }

            validate { credential ->
                val subject = credential.payload.subject
                val notBefore = credential.payload.notBefore?.time
                val now = Instant.now().toEpochMilli()

                if (subject.isNullOrBlank()) {
                    log.warn("JWT rejected: missing subject")
                    null
                } else if (notBefore != null && now < notBefore) {
                    log.warn("JWT rejected: token not yet valid (nbf)")
                    null
                } else {
                    JWTPrincipal(credential.payload)
                }
            }

            challenge { _, _ ->
                // Rate limit by IP (simple example - use a proper limiter in real prod)
                log.warn("Unauthorized JWT access from ${call.request.origin.remoteHost}")
                call.respond(HttpStatusCode.Unauthorized, "Unauthorized")
            }
        }
    }

    routing {
        authenticate("auth-jwt") {
            get("/v1/admin/users") {
                val principal = call.principal<JWTPrincipal>()!!
                val roles = principal.payload.getClaim("roles").asArray(String::class.java)?.toSet() ?: emptySet()

                if (!roles.contains("ADMIN")) {
                    log.warn("Access denied for subject=${principal.payload.subject} to /v1/admin/users")
                    call.respond(HttpStatusCode.Forbidden, "Insufficient privileges")
                    return@get
                }

                log.info("Admin users endpoint accessed by ${principal.payload.subject}")
                call.respond(HttpStatusCode.OK, listOf("user1", "user2"))
            }

            get("/v1/profile") {
                val principal = call.principal<JWTPrincipal>()!!
                val sub = principal.payload.subject
                log.info("Profile accessed by $sub")
                call.respond(HttpStatusCode.OK, "Profile data for $sub")
            }
        }

        // Health-check endpoint (no auth) for monitoring
        get("/health") {
            call.respond(HttpStatusCode.OK, "OK")
        }
    }

    if (environment.config.propertyOrNull("ktor.environment")?.getString() == "prod") {
        log.info("Applying production security headers")
        // In a full app you would install HSTS, CSP, etc. via features/plugins
    }
}
```

**Defense in Depth Layers**:
1. **Strong, rotating keys with `kid` support**:
   - `JwtKeyProvider` abstracts key loading and rotation, so you can change secrets or public keys without code changes.
   - Example: `val algorithm = keyProvider.getAlgorithm(kid)` ensures the correct key is used and unknown `kid` values are rejected.
2. **Strict claim and time validation at every service**:
   - `withIssuer(issuer)` and `withAudience(audience)` prevent token reuse across environments or services.
   - `notBefore` (`nbf`) check and leeway guard against clock skew and premature token use.
3. **Role-based access control (RBAC) enforced per endpoint**:
   - For admin endpoints, roles are checked explicitly:
   ```kotlin
   if (!roles.contains("ADMIN")) {
       call.respond(HttpStatusCode.Forbidden, "Insufficient privileges")
       return@get
   }
   ```
   - This avoids relying solely on the presence of a token for authorization.

**Additional Protections**:
- **Environment-specific configuration**: read issuer, audience, active key IDs, and secrets from environment/secret manager; use different values per environment to prevent token reuse between dev/stage/prod.
- **Rate limiting and anomaly detection**: log unauthorized and forbidden attempts with IP and subject, feed logs into SIEM/monitoring to detect token brute forcing, abuse, or mass scraping.
- **Graceful degradation and secure failure**: on key lookup failure or invalid token, return `401`/`403` with generic messages, never stack traces or key information, and keep core API responsive by caching keys and minimizing external dependencies for validation.

Storing passwords with weak or reversible algorithms makes offline cracking and account takeover much easier if your database is ever leaked.

