**SECURE VERSION**:

```kotlin
import java.security.SecureRandom
import java.sql.Connection
import java.sql.DriverManager
import java.sql.PreparedStatement
import java.sql.ResultSet
import java.util.Base64
import javax.crypto.SecretKeyFactory
import javax.crypto.spec.PBEKeySpec
import kotlin.system.measureTimeMillis

class AuthServiceSecure {
    private val dbUrl = "jdbc:postgresql://localhost/appdb"
    private val dbUser = "appuser"
    private val dbPass = "password"

    private val secureRandom = SecureRandom()

    // PBKDF2 parameters (tune for your environment)
    private val iterations = 120_000
    private val keyLengthBits = 256

    private fun getConnection(): Connection {
        return DriverManager.getConnection(dbUrl, dbUser, dbPass)
    }

    private fun generateSalt(lengthBytes: Int = 16): ByteArray {
        val salt = ByteArray(lengthBytes)
        secureRandom.nextBytes(salt)
        return salt
    }

    private fun hashPassword(password: CharArray, salt: ByteArray): ByteArray {
        val spec = PBEKeySpec(password, salt, iterations, keyLengthBits)
        val skf = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256")
        return skf.generateSecret(spec).encoded
    }

    data class PasswordHash(val saltB64: String, val hashB64: String, val iterations: Int)

    private fun encodePassword(password: CharArray): PasswordHash {
        val salt = generateSalt()
        val hash = hashPassword(password, salt)
        val encoder = Base64.getEncoder()
        return PasswordHash(
            saltB64 = encoder.encodeToString(salt),
            hashB64 = encoder.encodeToString(hash),
            iterations = iterations
        )
    }

    private fun verifyPassword(password: CharArray, stored: PasswordHash): Boolean {
        val decoder = Base64.getDecoder()
        val salt = decoder.decode(stored.saltB64)
        val expectedHash = decoder.decode(stored.hashB64)
        val spec = PBEKeySpec(password, salt, stored.iterations, expectedHash.size * 8)
        val skf = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256")
        val actualHash = skf.generateSecret(spec).encoded
        return constantTimeEquals(expectedHash, actualHash)
    }

    private fun constantTimeEquals(a: ByteArray, b: ByteArray): Boolean {
        if (a.size != b.size) return false
        var result = 0
        for (i in a.indices) {
            result = result or (a[i].toInt() xor b[i].toInt())
        }
        return result == 0
    }

    fun register(username: String, password: String) {
        require(username.length in 3..64) { "Invalid username length" }
        require(password.length in 8..128) { "Invalid password length" }

        val pwdHash = encodePassword(password.toCharArray())
        val sql = "INSERT INTO users(username, password_hash, salt, iterations) VALUES(?, ?, ?, ?)"

        getConnection().use { conn ->
            conn.prepareStatement(sql).use { ps: PreparedStatement ->
                ps.setString(1, username)
                ps.setString(2, pwdHash.hashB64)
                ps.setString(3, pwdHash.saltB64)
                ps.setInt(4, pwdHash.iterations)
                ps.executeUpdate()
            }
        }
    }

    fun login(username: String, password: String): Boolean {
        val sql = "SELECT password_hash, salt, iterations FROM users WHERE username = ?"
        var success = false

        val elapsed = measureTimeMillis {
            getConnection().use { conn ->
                conn.prepareStatement(sql).use { ps: PreparedStatement ->
                    ps.setString(1, username)
                    val rs: ResultSet = ps.executeQuery()
                    if (rs.next()) {
                        val stored = PasswordHash(
                            saltB64 = rs.getString("salt"),
                            hashB64 = rs.getString("password_hash"),
                            iterations = rs.getInt("iterations")
                        )
                        success = verifyPassword(password.toCharArray(), stored)
                    } else {
                        // Fake verification to keep timing similar
                        val dummySalt = generateSalt()
                        val dummyHash = hashPassword("invalid".toCharArray(), dummySalt)
                        constantTimeEquals(dummyHash, dummyHash)
                        success = false
                    }
                }
            }
        }

        // In real code, log in a central logger instead of println
        println("Login attempt for user='$username' success=$success took=${elapsed}ms")
        return success
    }
}
```

**Key Security Controls**:
- Uses PBKDF2WithHmacSHA256 with high iteration count to slow down brute-force attacks, even if hashes are leaked.
- Generates a cryptographically secure, unique salt per user and stores it alongside the hash, defeating rainbow tables and making each password crack independent.
- Uses parameterized SQL queries and basic input checks to prevent SQL injection that could expose the password hash database.

In production you need more than a strong hash: you must tune parameters per environment, throttle attackers, log securely, and monitor for abuse while still preserving user privacy.

**PRODUCTION PATTERN**:

```kotlin
import java.security.SecureRandom
import java.time.Instant
import java.util.Base64
import java.util.concurrent.ConcurrentHashMap
import javax.crypto.SecretKeyFactory
import javax.crypto.spec.PBEKeySpec

// Simulated environment config
enum class Env { DEV, STAGING, PROD }

data class SecurityConfig(
    val env: Env,
    val pbkdf2Iterations: Int,
    val pbkdf2KeyLengthBits: Int,
    val maxLoginAttemptsPerIpPerMin: Int,
    val maxLoginAttemptsPerUserPerMin: Int
)

object ConfigProvider {
    fun load(): SecurityConfig {
        val envName = System.getenv("APP_ENV") ?: "DEV"
        val env = Env.valueOf(envName.uppercase())
        return when (env) {
            Env.DEV -> SecurityConfig(env, 40_000, 256, 30, 30)
            Env.STAGING -> SecurityConfig(env, 80_000, 256, 20, 20)
            Env.PROD -> SecurityConfig(env, 150_000, 256, 10, 10)
        }
    }
}

// Simple in-memory rate limiter (per-node); use Redis or similar in real systems
class RateLimiter(private val windowSeconds: Long) {
    private data class Counter(var count: Int, var windowStart: Long)

    private val byIp = ConcurrentHashMap<String, Counter>()
    private val byUser = ConcurrentHashMap<String, Counter>()

    private fun allow(map: ConcurrentHashMap<String, Counter>, key: String, limit: Int): Boolean {
        val nowSec = Instant.now().epochSecond
        val counter = map.computeIfAbsent(key) { Counter(0, nowSec) }
        synchronized(counter) {
            if (nowSec - counter.windowStart >= windowSeconds) {
                counter.count = 0
                counter.windowStart = nowSec
            }
            if (counter.count >= limit) return false
            counter.count++
            return true
        }
    }

    fun allowIp(ip: String, limit: Int): Boolean = allow(byIp, ip, limit)
    fun allowUser(username: String, limit: Int): Boolean = allow(byUser, username, limit)
}

// Minimal logger abstraction
object AuditLogger {
    fun info(message: String, meta: Map<String, Any?> = emptyMap()) {
        println("INFO: $message | meta=$meta")
    }

    fun warn(message: String, meta: Map<String, Any?> = emptyMap()) {
        println("WARN: $message | meta=$meta")
    }

    fun error(message: String, meta: Map<String, Any?> = emptyMap()) {
        println("ERROR: $message | meta=$meta")
    }
}

class ProductionAuthService(private val config: SecurityConfig) {
    private val random = SecureRandom()
    private val encoder = Base64.getEncoder()
    private val decoder = Base64.getDecoder()
    private val rateLimiter = RateLimiter(windowSeconds = 60)

    data class StoredPassword(
        val hashB64: String,
        val saltB64: String,
        val iterations: Int
    )

    // In-memory user store for demonstration only
    private val userStore = ConcurrentHashMap<String, StoredPassword>()

    private fun generateSalt(lengthBytes: Int = 16): ByteArray {
        val salt = ByteArray(lengthBytes)
        random.nextBytes(salt)
        return salt
    }

    private fun hashPassword(password: CharArray, salt: ByteArray, iterations: Int): ByteArray {
        val spec = PBEKeySpec(password, salt, iterations, config.pbkdf2KeyLengthBits)
        val factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256")
        return factory.generateSecret(spec).encoded
    }

    private fun constantTimeEquals(a: ByteArray, b: ByteArray): Boolean {
        if (a.size != b.size) return false
        var result = 0
        for (i in a.indices) {
            result = result or (a[i].toInt() xor b[i].toInt())
        }
        return result == 0
    }

    fun register(username: String, password: String) {
        require(username.length in 3..64) { "Invalid username" }
        require(password.length in 12..128) { "Password too weak" }

        val salt = generateSalt()
        val hash = hashPassword(password.toCharArray(), salt, config.pbkdf2Iterations)
        val record = StoredPassword(
            hashB64 = encoder.encodeToString(hash),
            saltB64 = encoder.encodeToString(salt),
            iterations = config.pbkdf2Iterations
        )

        userStore[username.lowercase()] = record
        AuditLogger.info("User registered", mapOf("user" to username, "env" to config.env.name))
    }

    fun login(username: String, password: String, ip: String): Boolean {
        val normUser = username.lowercase()

        // Layer 1: rate limiting (IP and username)
        if (!rateLimiter.allowIp(ip, config.maxLoginAttemptsPerIpPerMin)) {
            AuditLogger.warn("Rate limit exceeded for IP", mapOf("ip" to ip))
            // Do not reveal rate limit reason to client
            return false
        }
        if (!rateLimiter.allowUser(normUser, config.maxLoginAttemptsPerUserPerMin)) {
            AuditLogger.warn("Rate limit exceeded for user", mapOf("user" to normUser, "ip" to ip))
            return false
        }

        val stored = userStore[normUser]
        if (stored == null) {
            // Fake verification to keep timing uniform
            val dummySalt = generateSalt()
            val dummyHash = hashPassword("invalid".toCharArray(), dummySalt, config.pbkdf2Iterations)
            constantTimeEquals(dummyHash, dummyHash)
            AuditLogger.warn(
                "Failed login (unknown user)",
                mapOf("user" to normUser, "ip" to ip)
            )
            return false
        }

        return try {
            val salt = decoder.decode(stored.saltB64)
            val expectedHash = decoder.decode(stored.hashB64)
            val actualHash = hashPassword(password.toCharArray(), salt, stored.iterations)
            val ok = constantTimeEquals(expectedHash, actualHash)

            if (ok) {
                AuditLogger.info(
                    "Successful login",
                    mapOf("user" to normUser, "ip" to ip, "env" to config.env.name)
                )
            } else {
                AuditLogger.warn(
                    "Failed login (bad password)",
                    mapOf("user" to normUser, "ip" to ip)
                )
            }
            ok
        } catch (e: Exception) {
            // Fail securely, do not leak details to client
            AuditLogger.error(
                "Authentication error",
                mapOf("user" to normUser, "ip" to ip, "error" to e.javaClass.simpleName)
            )
            false
        }
    }
}

fun main() {
    val config = ConfigProvider.load()
    val auth = ProductionAuthService(config)

    // Example usage
    auth.register("alice", "VeryStrongPassword123!")
    val ok = auth.login("alice", "VeryStrongPassword123!", "203.0.113.10")
    println("Login success: $ok")
}
